command:
// Deal the Heist Hand
// First run: imports the three deck tables from the Heist Deck compendium.
// Every run: draws 3 Obstacles, 1 Treasure, 2 People — never repeating a card.
// To start fresh: open each world table, click Reset, then run again.

const MODULE_ID = "heist-deck-compendium";

async function ensureTable(name) {
  const good = game.tables.find(t =>
    t.getFlag(MODULE_ID, "deck") === name &&
    t.results.contents[0]?.documentUuid &&
    t.replacement === false
  );
  if (good) return good;

  for (const t of game.tables.filter(t => t.getFlag(MODULE_ID, "deck") === name))
    await t.delete();

  const pack = game.packs.get(`${MODULE_ID}.heist-tables`);
  if (!pack) throw new Error("Heist Deck module not found or not enabled.");
  const idx = await pack.getIndex();
  const entry = idx.find(e => e.name === name);
  if (!entry) throw new Error(`Table '${name}' not found in compendium.`);

  const table = await game.tables.importFromCompendium(pack, entry._id);
  await table.setFlag(MODULE_ID, "deck", name);
  return table;
}

async function drawN(table, n) {
  const results = [];
  for (let i = 0; i < n; i++) {
    const { results: drawn } = await table.draw({ displayChat: false });
    if (!drawn.length) break;
    results.push(...drawn.filter(Boolean));
  }
  return results;
}

function cardLink(result) {
  const label = result.name ?? result.text ?? "Unknown";
  return result.documentUuid ? `@UUID[${result.documentUuid}]{${label}}` : label;
}

function rows(label, results) {
  if (!results.length)
    return `<p><b>${label}:</b> <em>deck empty — reset the table to draw more</em></p>`;
  return results.map(r => `<p><b>${label}:</b> ${cardLink(r)}</p>`).join("\n");
}

const obstacles = await ensureTable("Obstacles");
const treasures = await ensureTable("Treasures");
const people    = await ensureTable("People");

const content = [
  "<h3>Heist Hand</h3>",
  rows("Obstacle", await drawN(obstacles, 3)),
  rows("Treasure", await drawN(treasures, 1)),
  rows("People",   await drawN(people, 2)),
].join("\n");

ChatMessage.create({ content, speaker: { alias: "Heist Deck" } });
